import java.util.TreeMap;

class SORTracker {

    private TreeMap<Integer, TreeMap<String, Integer>> map;
    private int queryCount;

    public SORTracker() {
        map = new TreeMap<>((a, b) -> b - a);
        queryCount = 0;
    }

    public void add(String name, int score) {
        map.computeIfAbsent(score, k -> new TreeMap<>()).put(name, 1);
    }

    public String get() {
        queryCount++;
        int score = map.firstKey();
        int count = map.get(score).size();
        int index = queryCount;
        while (count < index) {
            map.remove(score);
            index -= count;
            if (map.isEmpty()) {
                break;
            }
            score = map.firstKey();
            count = map.get(score).size();
        }
        String name = map.get(score).firstKey();
        if (map.get(score).size() == 1) {
            map.remove(score);
        } else {
            map.get(score).remove(name);
        }
        return name;
    }
}
